xpath.script:
(function () {
    const root = document.documentElement;
    if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) {
        return;
    }
    root.classList.add("x_page_transition_entering");
    const enter = () => {
        root.classList.add("x_page_transition_ready");
        requestAnimationFrame(() => root.classList.remove("x_page_transition_entering"));
    };
    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", enter, { once: true });
    } else {
        enter();
    }
    document.addEventListener("click", (event) => {
        const link = event.target.closest("a[href]");
        if (!link || event.defaultPrevented || event.button !== 0) {
            return;
        }
        if (event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) {
            return;
        }
        if (link.target && link.target !== "_self") {
            return;
        }
        const url = new URL(link.href, window.location.href);
        if (url.origin !== window.location.origin) {
            return;
        }
        if (url.hash && url.pathname === window.location.pathname) {
            return;
        }
        root.classList.add("x_page_transition_leaving");
    });
    window.addEventListener("pageshow", () => {
        root.classList.remove("x_page_transition_leaving");
    });
})();
